const PRINCIPLES=[
  {t:"Invest in Human Skills",d:"One day the only jobs people will do will be jobs only people can do. Relationship-building, political navigation, stakeholder trust, and cross-cultural communication cannot be automated. In policy, a phone call to the right Joint Secretary matters more than a 50-page report."},
  {t:"Find Your Competitive Advantage",d:"Sample 10 flavours before you buy one. You will always lose to someone who is genuinely enjoying their work. India's policy ecosystem is broad enough to reward almost any combination of skills and interests."},
  {t:"Show, Don't Tell",d:"A policy brief you actually wrote beats listing 'strong analytical skills' on your resume. A blog post analysing open data beats claiming 'data proficiency.' Build a portfolio of visible work."},
  {t:"Increase Your Luck Surface Area",d:"Spread the word and literally become luckier. Attend events, write publicly, share work on LinkedIn, join communities like PPI. Most policy jobs are never publicly advertised. They flow through networks."},
  {t:"Shun Competition, Identify Gaps",d:"Don't fight for the same 50 LAMP spots or 1,000 UPSC seats. Climate policy, AI governance, cooperative economics, civic tech are all fields with more openings than qualified applicants."},
  {t:"Shape Your Values",d:"Storytelling counts. A large chunk of hiring is a vibe check. Know where your lines are. Coherence, not perfection, is what interviewers look for."}
];

const FIVE_R=[
  {s:"Reflect",d:"Why do you want to work in policy? What motivates you? What are you willing to sacrifice? Your 'why' shapes every subsequent decision."},
  {s:"Research",d:"Which organisations work in your chosen space? What do they hire for? Look at LinkedIn profiles of people in those roles. Read their publications. Attend their events."},
  {s:"Ready",d:"Resume, LinkedIn, portfolio. Don't just write 'strong writing skills'; link to the brief you wrote. Don't just list 'data analysis'; link to your analysis."},
  {s:"Reach Out",d:"Apply with tailored applications. Simultaneously, reach out to practitioners. A referral from inside is worth more than a perfect CV submitted through a portal."},
  {s:"Repeat",d:"If first cycle doesn't work, iterate. Most successful policy professionals took 2-3 attempts. Persistence is the meta-skill."}
];


